    TaskScheduler::Execute("getgenv().WebSocket = {connect = function(url) assert(type(url) == \"string\", \"WebSocket URL must be a string\") local function v(u) if type(u) ~= \"string\" then return false, \"WebSocket URL must be a string\" end local t = u:match(\"^%s*(.-)%s*$\") or u local s, r = t:match(\"^(%a[%w+%.%-]*)://(.*)$\") if not s or (s ~= \"ws\" and s ~= \"wss\") then return false, \"WebSocket URL must start with ws:// or wss://\" end if r == \"\" or r:find(\"%s\") or r:sub(1, 1) == \"/\" then return false, \"WebSocket URL must include a host\" end local a = r:match(\"^([^/%?#]+)\") if not a or a == \"\" then return false, \"WebSocket URL must include a host\" end a = a:gsub(\"^.-@\", \"\") local h, p if a:sub(1, 1) == \"[\" then local i = a:match(\"^%[[^%]]+%]\") if not i then return false, \"Invalid IPv6 host\" end h = i p = a:sub(#i + 1) else h, p = a:match(\"^([^:]+):?(.*)$\") if p == \"\" then p = nil end end if not h or h == \"\" then return false, \"WebSocket URL must include a host\" end if p and p:sub(1, 1) == \":\" then p = p:sub(2) end if p and p ~= \"\" then if not p:match(\"^%d+$\") then return false, \"Invalid port\" end local n = tonumber(p) if not n or n < 1 or n > 65535 then return false, \"Invalid port\" end end return true end local ok, err = v(url) assert(ok, err or (\"Invalid WebSocket URL: \" .. tostring(url))) local Signal = {} Signal.__index = Signal function Signal.new() return setmetatable({_connections = {}}, Signal) end function Signal:Connect(callback) local connection = {callback = callback, connected = true} table.insert(self._connections, connection) return {Disconnect = function() connection.connected = false for i, conn in ipairs(self._connections) do if conn == connection then table.remove(self._connections, i) break end end end} end function Signal:Fire(...) for _, connection in ipairs(self._connections) do if connection.connected then task.spawn(connection.callback, ...) end end end local socket = game:GetService(\"WebSocketService\"):CreateClient(url) local websocket_connection = setmetatable({ClassName = \"WebSocket\", __OBJECT = url, __OBJECT_ACTIVE = true, __OBJECT_MESSAGE = Signal.new(), __OBJECT_CLOSE = Signal.new(), __SESSION = socket}, {__index = function(self, index) if not rawget(self, \"__OBJECT_ACTIVE\") then error(\"WebSocket is closed.\") end if index == \"OnMessage\" then return rawget(self, \"__OBJECT_MESSAGE\") end if index == \"OnClose\" then return rawget(self, \"__OBJECT_CLOSE\") end if index == \"Send\" then return function(_, message, is_binary) if not rawget(self, \"__OBJECT_ACTIVE\") then error(\"WebSocket is closed.\") end local session = rawget(self, \"__SESSION\") if session and session.Send then session:Send(message) end end end if index == \"Close\" then return function(_) if not rawget(self, \"__OBJECT_ACTIVE\") then error(\"WebSocket is closed.\") end rawset(self, \"__OBJECT_ACTIVE\", false) local closeSignal = rawget(self, \"__OBJECT_CLOSE\") if closeSignal then closeSignal:Fire() end local session = rawget(self, \"__SESSION\") if session and session.Close then session:Close() end end end end, __newindex = function() error(\"WebSocket is readonly.\") end, __type = \"WebSocket\"}) websocket_connection.__OBJECT_CLOSE:Connect(function() websocket_connection.__OBJECT_ACTIVE = false if socket and socket.Close then socket:Close() end end) game:GetService(\"Players\").LocalPlayer.OnTeleport:Connect(function(teleportState) if teleportState == Enum.TeleportState.Started and websocket_connection.__OBJECT_ACTIVE then websocket_connection:Close() end end) if socket.MessageReceived then socket.MessageReceived:Connect(function(...) websocket_connection.__OBJECT_MESSAGE:Fire(...) end) end return websocket_connection end}");
